import mysql.connector
from mysql.connector import errorcode

def enable_local_infile(cursor):
    cursor.execute("SET GLOBAL local_infile = 1")

def import_data(file_path, table_name, db_config):
    try:
        conn = mysql.connector.connect(**db_config)
        cursor = conn.cursor()
        enable_local_infile(cursor)
        
        load_data_query = "LOAD DATA LOCAL INFILE '{}' INTO TABLE {} FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\n' IGNORE 1 LINES".format(file_path, table_name)
        cursor.execute(load_data_query)
        conn.commit()
        
        print("Data imported successfully into table {}".format(table_name))
    except mysql.connector.Error as err:
        if err.errno == errorcode.ER_ACCESS_DENIED_ERROR:
            print("Something is wrong with your user name or password")
        elif err.errno == errorcode.ER_BAD_DB_ERROR:
            print("Database does not exist")
        else:
            print(err)
    finally:
        cursor.close()
        conn.close()

if __name__ == "__main__":
    db_config = {
        'user': 'your_username',
        'password': 'your_password',
        'host': 'localhost',
        'database': 'your_database',
        'allow_local_infile': True
    }
    
    file_path = input("Enter the file path for import: ")
    table_name = input("Enter the table name: ")
    
    import_data(file_path, table_name, db_config)